import java.util.*;
class Solution {

    public static ArrayList<Integer> findParcelDeliveryCount(int n, int m, int[][] path, int[][] delivery_plan){
    	List<Integer>[] tree_graph = new ArrayList[n+1];

    	for(int i=1 ; i<=n ; i++){
    		tree_graph[i] = new ArrayList<>();
    	}

    	for(int[] i : path){
    		int x = i[0];
    		int y = i[1];
    		tree_graph[x].add(y);
    		tree_graph[y].add(x);
    	}

    	int[] root = new int[n + 1];
    	int[] tree_depth = new int[n+1];

    	boolean[] already_deliveried = new boolean[n+1];

    	depthFirstSearch(1, tree_graph, already_deliveried, root, tree_depth);

		if (delivery_plan == null || delivery_plan.length == 0) {
			return new ArrayList<>();
		}

    	int[] packages = new int[n+1];

    	for(int[] i : delivery_plan){
    		int start_office = i[0];
    		int end_office = i[1];


			if (start_office < 1 || start_office > n || end_office < 1 || end_office > n) {
				throw new IllegalArgumentException("Invalid chakra zone indices: " + start_office + ", " + end_office);
			}


    		while(tree_depth[start_office] > tree_depth[end_office]){
    			packages[start_office]++;
    			start_office = root[start_office];
    		}

    		while(tree_depth[end_office] > tree_depth[start_office]){
    			packages[end_office]++;
    			end_office = root[end_office];
    		}

    		while(start_office != end_office){
    			packages[start_office]++;
    			packages[end_office]++;
    			start_office = root[start_office];
    			end_office = root[end_office];
    		}

    		packages[start_office]++;
    	}

    	ArrayList<Integer> answer = new ArrayList<>();
    	for(int i=1 ; i<=n ; i++){
    		answer.add(packages[i]);
    	}

    	return answer;
    }

    public static void depthFirstSearch(int node, List<Integer>[] tree_graph, boolean[] already_deliveried, int[] parent, int[] tree_depth){
    	already_deliveried[node] = true;

    	for(int i : tree_graph[node]){
    		if(!already_deliveried[i]){
    			parent[i] = node;
    			tree_depth[i] = tree_depth[node] + 1;
    			depthFirstSearch(i, tree_graph, already_deliveried, parent, tree_depth);
    		}
    	}
    }
}

