import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

class Test {
    private final Solution solution = new Solution();

    @Test
    public void testWithNoDeliveryPlan() {
        int n = 5, m = 3;
        int[][] path = {{1, 2}, {1, 3}, {3, 4}, {3, 5}};
        int[][] delivery_plan = {};
        List<Integer> expected = new ArrayList<>();
        assertEquals(expected, solution.findParcelDeliveryCount(n, m, path, delivery_plan));
    }

    @Test
    public void testSingleOfficeNoDeliveries() {
        int n = 1, m = 0;
        int[][] path = {};  // No paths since there's only one office
        int[][] delivery_plan = {};
        List<Integer> expected = new ArrayList<>();
        assertEquals(expected, solution.findParcelDeliveryCount(n, m, path, delivery_plan));
    }

    @Test
    public void testDisconnectedOffices() {
        int n = 4, m = 2;
        int[][] path = {};  // No paths, all offices are disconnected
        int[][] delivery_plan = {{1, 4}, {2, 3}};
        List<Integer> expected = Arrays.asList(1, 1, 1, 1); // Each office receives one parcel
        assertEquals(expected, solution.findParcelDeliveryCount(n, m, path, delivery_plan));
    }

    @Test
    public void testInvalidChakraZoneIndices() {
        int n = 5, m = 3;
        int[][] path = {{1, 2}, {1, 3}, {3, 4}, {3, 5}};
        int[][] delivery_plan = {{1, 3}, {2, 5}, {1, 4}};
        assertThrows(IllegalArgumentException.class, () -> {
            solution.findParcelDeliveryCount(n, m, path, new int[][]{{-1, 5}});
        }, Invalid chakra zone indices");
